library(shiny)
library(readxl)

# ====== 1. 安全隨機函數 ======
resample <- function(x, ...) {
  if (length(x) <= 1) x else sample(x, ...)
}

# ====== 2. CSS 樣式優化 ======
style <- "
  .flashcard-container {
    display: flex;
    justify-content: center;
    align-items: center;
    height: 350px;
    margin-bottom: 20px;
  }
  .flashcard-btn {
    width: 100%;
    max-width: 500px;
    height: 300px;
    background-color: #ffffff;
    border: 2px solid #dee2e6;
    border-radius: 20px;
    box-shadow: 0 6px 12px rgba(0,0,0,0.1);
    color: #333;
    transition: transform 0.1s, box-shadow 0.2s;
    padding: 0;
    overflow: hidden;
  }
  .flashcard-btn:hover {
    box-shadow: 0 10px 20px rgba(0,0,0,0.15);
    border-color: #007bff;
  }
  .flashcard-btn:active {
    transform: scale(0.98);
  }
  .card-content-wrapper {
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    height: 100%;
    width: 100%;
    padding: 30px;
    overflow-y: auto;
    max-height: 295px;
    font-size: 24px;
    font-weight: bold;
    line-height: 1.6;
    white-space: pre-wrap; 
    word-wrap: break-word;
  }
  .card-status-hint {
    font-size: 13px;
    font-weight: normal;
    color: #aaa;
    margin-bottom: 12px;
    text-transform: uppercase;
    letter-spacing: 1.5px;
    text-align: center; /* 提示詞固定置中 */
    width: 100%;
  }
  .btn-group-container {
    display: flex;
    justify-content: center;
    gap: 12px;
    margin-top: 10px;
  }
  .status-btn { 
    width: 100%; 
    max-width: 130px; 
    font-size: 16px; 
    padding: 12px; 
    border-radius: 10px; 
    font-weight: bold;
  }
  .control-panel {
    margin-top: 20px;
    padding: 20px;
    background-color: #fcfcfc;
    border-radius: 15px;
    border: 1px solid #eee;
    box-shadow: inset 0 1px 3px rgba(0,0,0,0.05);
  }
"

# ====== 3. UI 介面 ======
ui <- fluidPage(
  tags$head(
    tags$style(HTML(style)),
    tags$meta(name="viewport", content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no")
  ),
  titlePanel("Flashcards 萬用版"),
  
  tabsetPanel(
    tabPanel("主學習模式",
             br(),
             div(class = "control-panel",
                 fileInput("upload_file", "📁 步驟 1：選擇您的 Excel 題庫 (.xlsx)",
                           accept = c(".xlsx"),
                           buttonLabel = "瀏覽...",
                           placeholder = "尚未選擇檔案")
             ),
             
             div(class = "flashcard-container",
                 actionButton("flip", label = uiOutput("card_content"), class = "flashcard-btn")
             ),
             
             div(class = "btn-group-container",
                 actionButton("again", "不會", class = "btn-danger status-btn"),
                 actionButton("hard", "不熟", class = "btn-warning status-btn"),
                 actionButton("good", "會了", class = "btn-success status-btn")
             ),
             
             hr(),
             actionButton("restart", "🔄 重新開始本檔案隨機一輪", class = "btn-default btn-block"),
             
             h4(textOutput("progress"), style="text-align:center; margin-top: 20px; color: #888;")
    ),
    
    tabPanel("錯題複習模式",
             br(),
             div(class = "flashcard-container",
                 actionButton("flip2", label = uiOutput("review_card_content"), class = "flashcard-btn")
             ),
             div(class = "btn-group-container",
                 actionButton("next_w", "下一個 (保留)", class = "btn-warning status-btn"),
                 actionButton("good2", "我會了 (移除)", class = "btn-success status-btn")
             ),
             hr(),
             actionButton("restart_review", "🚀 開始 / 重新隨機一輪錯題", class = "btn-lg btn-block btn-primary"),
             h4(textOutput("review_progress"), style="text-align:center; margin-top: 20px; color: #888;")
    )
  )
)

# ====== 4. Server 邏輯 ======
server <- function(input, output, session) {
  
  cards <- reactiveVal(data.frame(id=integer(), front=character(), back=character()))
  wrong_ids <- reactiveVal(c())
  order <- reactiveVal(NULL)
  index <- reactiveVal(1)
  show_answer <- reactiveVal(FALSE)
  
  review_order <- reactiveVal(NULL)
  review_index <- reactiveVal(1)
  show_answer2 <- reactiveVal(FALSE)
  
  # --- 邏輯 A：處理檔案上傳 ---
  observeEvent(input$upload_file, {
    req(input$upload_file)
    tryCatch({
      raw <- read_excel(input$upload_file$datapath)
      smart_split <- function(x) {
        x <- as.character(x)
        x <- gsub("\r\n|\n", "<br>", x)
        target_symbols <- "➢|◼|□|✅|●|○|•|❑|▲|▼|※"
        x <- gsub(paste0("(?=", target_symbols, ")"), "<br>", x, perl=TRUE)
        x <- gsub("^<br>", "", x)
        return(x)
      }
      df <- data.frame(id = 1:nrow(raw), front = smart_split(raw[[1]]), back = smart_split(raw[[2]]), stringsAsFactors = FALSE)
      cards(df); wrong_ids(c()); order(resample(df$id)); index(1); show_answer(FALSE)
      showNotification(paste0("上傳成功！共 ", nrow(df), " 筆資料。"), type = "message")
    }, error = function(e) {
      showNotification("檔案讀取失敗", type = "error")
    })
  })
  
  # --- 邏輯 B：主學習渲染 (修正對齊) ---
  output$card_content <- renderUI({
    ord <- order(); idx <- index(); df <- cards()
    if (is.null(ord) || nrow(df) == 0) return(div(class="card-content-wrapper", "請先上傳 Excel 檔案"))
    if (idx > length(ord)) return(div(class="card-content-wrapper", style="color: #28a745;", "🎉 本輪已完成！"))
    
    row <- df[df$id == ord[idx], ]
    
    # 核心邏輯：題目時 center，答案時 left
    align_style <- if(!show_answer()) "center" else "left"
    txt <- if(!show_answer()) row$front else row$back
    color <- if(!show_answer()) "#333" else "#007bff"
    label_hint <- if(!show_answer()) "QUESTION" else "ANSWER"
    
    div(class="card-content-wrapper",
        div(class="card-status-hint", label_hint),
        div(style = paste0("color:", color, "; width: 100%; text-align:", align_style, ";"), HTML(txt))
    )
  })
  
  observeEvent(input$flip, { show_answer(!show_answer()) })
  
  process_main <- function(res) {
    if (is.null(order()) || index() > length(order())) return()
    if (res != "會") {
      wrong_ids(unique(c(wrong_ids(), order()[index()])))
    }
    index(index() + 1); show_answer(FALSE)
  }
  
  observeEvent(input$again, { process_main("不會") })
  observeEvent(input$hard, { process_main("不熟") })
  observeEvent(input$good, { process_main("會") })
  
  observeEvent(input$restart, {
    if(nrow(cards()) > 0) {
      order(resample(cards()$id)); index(1); show_answer(FALSE)
    }
  })
  
  output$progress <- renderText({
    if (is.null(order())) return("")
    paste0("進度：", min(index(), length(order())), " / ", length(order()))
  })
  
  # --- 邏輯 C：錯題複習渲染 (修正對齊) ---
  output$review_card_content <- renderUI({
    ord <- review_order(); idx <- review_index(); df <- cards()
    if (is.null(ord)) return(div(class="card-content-wrapper", "請點擊按鈕開始複習"))
    if (length(ord) == 0) return(div(class="card-content-wrapper", style="color: #28a745;", "目前沒有錯題！"))
    if (idx > length(ord)) return(div(class="card-content-wrapper", style="color: #17a2b8;", "✅ 複習結束！"))
    
    row <- df[df$id == ord[idx], ]
    
    # 核心邏輯：題目時 center，答案時 left
    align_style <- if(!show_answer2()) "center" else "left"
    txt <- if(!show_answer2()) row$front else row$back
    color <- if(!show_answer2()) "#333" else "#dc3545"
    label_hint <- if(!show_answer2()) "REVIEW (Tap to flip)" else "CORRECT ANSWER"
    
    div(class = "card-content-wrapper",
        div(class = "card-status-hint", label_hint),
        div(style = paste0("color:", color, "; width: 100%; text-align:", align_style, ";"), HTML(txt))
    )
  })
  
  observeEvent(input$flip2, { show_answer2(!show_answer2()) })
  
  observeEvent(input$good2, {
    if (is.null(review_order()) || review_index() > length(review_order())) return()
    wrong_ids(setdiff(wrong_ids(), review_order()[review_index()]))
    review_index(review_index() + 1); show_answer2(FALSE)
  })
  
  observeEvent(input$next_w, {
    if (is.null(review_order()) || review_index() > length(review_order())) return()
    review_index(review_index() + 1); show_answer2(FALSE)
  })
  
  observeEvent(input$restart_review, {
    ids <- wrong_ids()
    if (length(ids) > 0) {
      review_order(resample(ids)); review_index(1); show_answer2(FALSE)
    } else {
      showNotification("沒有錯題可以複習！", type = "warning")
      review_order(c())
    }
  })
  
  output$review_progress <- renderText({
    paste0("目前待複習總數：", length(wrong_ids()))
  })
}

shinyApp(ui, server)
